BEGIN TRANSACTION;
CREATE TABLE beliefs (
            id        INTEGER PRIMARY KEY AUTOINCREMENT,
            content   TEXT UNIQUE,
            topic     TEXT,
            confidence REAL DEFAULT 0.75,
            source    TEXT DEFAULT 'injector'
        , belief_type TEXT DEFAULT 'opinion', source_url TEXT DEFAULT '', retrieved_date TEXT DEFAULT '', created_at TEXT DEFAULT '', is_identity INTEGER DEFAULT 0, embedding BLOB, locked INTEGER DEFAULT 0);
CREATE TABLE bridge_history (
        id              INTEGER PRIMARY KEY AUTOINCREMENT,
        belief_a_id     INTEGER,
        belief_b_id     INTEGER,
        topic_a         TEXT,
        topic_b         TEXT,
        content_a       TEXT,
        content_b       TEXT,
        shared_concepts TEXT,
        bridge_score    REAL,
        bridge_text     TEXT,
        promoted        INTEGER DEFAULT 0,
        created_at      REAL
    );
CREATE TABLE contra_resolved (
                topic        TEXT PRIMARY KEY,
                resolved_at  TEXT,
                belief_count INTEGER DEFAULT 0
            );
CREATE TABLE metabolism_log (
                id         INTEGER PRIMARY KEY AUTOINCREMENT,
                ts         REAL,
                event_type TEXT,
                topic      TEXT,
                added      INTEGER,
                detail     TEXT
            );
CREATE INDEX idx_beliefs_topic ON beliefs(topic);
CREATE INDEX idx_beliefs_confidence ON beliefs(confidence DESC);
CREATE INDEX idx_beliefs_topic_conf ON beliefs(topic, confidence DESC);
CREATE INDEX idx_bridge_score ON bridge_history(bridge_score DESC);
DELETE FROM "sqlite_sequence";
COMMIT;
